code = """import json
import re

# Load the physical activity papers
with open(var_functions.query_db:2, 'r') as f:
    papers = json.load(f)

print("Loaded", len(papers), "papers")

# Extract year from text
def get_year(text):
    start_text = text[:2000]
    if "2016" in start_text:
        return 2016
    return None

# Find 2016 papers
papers_2016 = []
for paper in papers:
    if get_year(paper['text']) == 2016:
        title = paper['filename'].replace('.txt', '')
        papers_2016.append({'title': title, 'year': 2016})

print("Found", len(papers_2016), "papers from 2016")
result = json.dumps(papers_2016)
print('__RESULT__:')
print(result)"""

